'use client';

import Link from 'next/link';
import { Product } from '@/types';
import { Package } from 'lucide-react';

interface ProductCardProps {
    product: Product;
}

export default function ProductCard({ product }: ProductCardProps) {
    return (
        <Link href={`/product/${product.id}`} className="group bg-white rounded-2xl overflow-hidden border border-[#e8e4dd] shadow-sm hover:shadow-lg transition-all duration-300 hover:-translate-y-1 hover:border-[#b8960c]/30">
            <div className="aspect-square bg-[#fafaf7] flex items-center justify-center overflow-hidden relative">
                {product.images?.[0] ? (
                    <>
                        <img
                            src={product.images[0]}
                            alt={product.name}
                            loading="lazy"
                            className="w-[80%] h-[80%] object-contain mix-blend-multiply group-hover:scale-110 transition-transform duration-500"
                            onError={(e) => {
                                e.currentTarget.style.display = 'none';
                                const sibling = e.currentTarget.nextElementSibling as HTMLElement | null;
                                if (sibling) sibling.classList.remove('hidden');
                            }}
                        />
                        <div className="hidden absolute inset-0 w-full h-full flex flex-col items-center justify-center text-slate-400 bg-[#f5f3ee]">
                            <Package size={48} />
                            <span className="text-xs font-semibold mt-2">Image unavailable</span>
                        </div>
                    </>
                ) : (
                    <div className="w-full h-full flex items-center justify-center text-slate-300">
                        <Package size={48} />
                    </div>
                )}
            </div>
            <div className="p-4 border-t border-[#fafaf7]">
                <h3 className="font-bold text-[#1a1a1a] text-sm truncate group-hover:text-[#b8960c] transition-colors">{product.name}</h3>
                <div className="flex items-center gap-2 mt-2">
                    <span className="text-lg font-bold text-[#1a1a1a]">RM {product.price.toFixed(2)}</span>
                    {product.compare_at_price && product.compare_at_price > product.price && (
                        <span className="text-sm font-medium text-slate-400 line-through">RM {product.compare_at_price.toFixed(2)}</span>
                    )}
                </div>
                {product.stock <= 0 && (
                    <span className="inline-block mt-2 text-xs font-bold text-amber-600 bg-amber-50 border border-amber-100 px-2.5 py-1 rounded">Out of Stock</span>
                )}
            </div>
        </Link>
    );
}
